const raw = $('Supabase Fetch').item.json.master_profile;
let profile = null;
try { profile = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { profile = null; }

const missing = [];
const addMissing = (label) => { if (!missing.includes(label)) missing.push(label); };
const hasProfile = profile && typeof profile === 'object';

if (!hasProfile) {
  addMissing('your resume data');
} else {
  if (!profile.name || !String(profile.name).trim()) addMissing('your full name');
  const contact = profile.contact || {};
  if (!contact.email && !contact.phone) addMissing('a contact email or phone number');
  if (!profile.summary || !String(profile.summary).trim()) addMissing('a short professional summary');
  const hasSkills = Array.isArray(profile.skills) && profile.skills.some((s) => {
    const items = Array.isArray(s?.items) ? s.items.join(', ') : (s?.items ?? s?.skills);
    return items && String(items).trim();
  });
  if (!hasSkills) addMissing('your key skills');
  if (!Array.isArray(profile.education) || profile.education.length === 0) addMissing('your education details');
  if (!Array.isArray(profile.work_experience) || profile.work_experience.length === 0) addMissing('your work experience');
  if (!Array.isArray(profile.projects) || profile.projects.length === 0) addMissing('your projects');
}

const isSufficient = missing.length === 0;
let prompt = '';
if (!isSufficient) {
  if (!hasProfile) {
    prompt = 'Your profile is currently empty. Please upload your resume PDF or send your professional details (starting with your full name) to establish your baseline profile.';
  } else {
    prompt = 'Your profile is incomplete. Please provide your ' + missing[0] + ' next to complete your profile. You can paste the text here or upload your resume PDF.';
  }
}

return [{ json: { ...$input.item.json, profile_status: { isSufficient, missing, prompt } } }];

const raw = $input.item.json.master_profile
  ?? $('Supabase Fetch').item.json.master_profile;

if (!raw) return [{ json: { text: "📭 No profile found. Send me your resume PDF or tell me about yourself!" } }];

let p;
try { p = typeof raw === 'string' ? JSON.parse(raw) : raw; }
catch(e) { return [{ json: { text: "❌ Could not read profile data. Try uploading your resume PDF again." } }]; }

if (!p || typeof p !== 'object') return [{ json: { text: "📭 No profile found. Send me your resume PDF!" } }];

const hasData = p.name || p.summary || p.tagline
  || (p.skills && p.skills.length > 0)
  || (p.work_experience && p.work_experience.length > 0)
  || (p.education && p.education.length > 0)
  || (p.projects && p.projects.length > 0)
  || (p.certifications && p.certifications.length > 0)
  || (p.contact && (p.contact.email || p.contact.phone));

if (!hasData) return [{ json: { text: "📭 Your profile appears empty. Please upload your resume PDF or tell me your details!" } }];

let msg = `*Master Resume Profile*\n━━━━━━━━━━━━━━━━━━━━\n\n`;

if (p.name) msg += `*${p.name}*\n`;
if (p.tagline) msg += `_${p.tagline}_\n`;
if (p.name || p.tagline) msg += `\n`;

if (p.contact) {
  const c = p.contact;
  const hasContact = c.email || c.phone || c.linkedin_display || c.linkedin_url || c.github_display || c.github_url || c.portfolio_display || c.portfolio_url;
  if (hasContact) {
    msg += `*Contact Details*\n`;
    if (c.email) msg += `  Email: ${c.email}\n`;
    if (c.phone) msg += `  Phone: ${c.phone}\n`;
    if (c.linkedin_display || c.linkedin_url) {
      if (c.linkedin_display && c.linkedin_url && c.linkedin_display !== c.linkedin_url) msg += `  LinkedIn: ${c.linkedin_display} (${c.linkedin_url})\n`;
      else msg += `  LinkedIn: ${c.linkedin_url || c.linkedin_display}\n`;
    }
    if (c.github_display || c.github_url) {
      if (c.github_display && c.github_url && c.github_display !== c.github_url) msg += `  GitHub: ${c.github_display} (${c.github_url})\n`;
      else msg += `  GitHub: ${c.github_url || c.github_display}\n`;
    }
    if (c.portfolio_display || c.portfolio_url) {
      if (c.portfolio_display && c.portfolio_url && c.portfolio_display !== c.portfolio_url) msg += `  Portfolio: ${c.portfolio_display} (${c.portfolio_url})\n`;
      else msg += `  Portfolio: ${c.portfolio_url || c.portfolio_display}\n`;
    }
    msg += `\n`;
  }
}
if (p.summary) msg += `*Professional Summary*\n${p.summary}\n\n`;

if (p.education && p.education.length > 0) {
  msg += `*Education*\n`;
  p.education.forEach(e => {
    msg += `    - *${e.degree}*\n    ${e.institution}\n`;
    if (e.score) msg += `    Score: ${e.score}\n`;
    if (e.year) msg += `    Year: ${e.year}\n`;
  });
  msg += `\n`;
}

if (p.work_experience && p.work_experience.length > 0) {
  msg += `*Work Experience*\n`;
  p.work_experience.forEach(w => {
    msg += `\n  *${w.title}* at ${w.company}`;
    if (w.location) msg += `, ${w.location}`;
    msg += `\n`;
    if (w.start_date) msg += `  _${w.start_date}${w.end_date ? ' – ' + w.end_date : ' – Present'}_\n`;
    if (w.bullet_points && w.bullet_points.length > 0)
      w.bullet_points.forEach(b => msg += `        - ${b}\n`);
  });
  msg += `\n`;
}

if (p.projects && p.projects.length > 0) {
  msg += `*Projects*\n`;
  p.projects.forEach(proj => {
    msg += `\n  *${proj.name}*\n`;
    if (proj.tech_stack) msg += `  _${proj.tech_stack}_\n`;
    if (proj.duration) msg += `  _${proj.duration}_\n`;
    if (proj.link_display || proj.link_url) {
      if (proj.link_display && proj.link_url && proj.link_display !== proj.link_url) msg += `  🔗 ${proj.link_display} (${proj.link_url})\n`;
      else msg += `  🔗 ${proj.link_url || proj.link_display}\n`;
    }
    if (proj.bullet_points && proj.bullet_points.length > 0)
      proj.bullet_points.forEach(b => msg += `        - ${b}\n`);
  });
  msg += `\n`;
}

if (p.skills && p.skills.length > 0) {
  msg += `*Technical Skills*\n`;
  p.skills.forEach(s => msg += `    - *${s.category || 'Skill'}:* ${s.items || s}\n`);
  msg += `\n`;
}

if (p.certifications && p.certifications.length > 0) {
  msg += `*Certifications*\n`;
  p.certifications.forEach(cert => {
    msg += `    - *${cert.name}*\n    ${cert.issuer}`;
    if (cert.year) msg += ` (${cert.year})`;
    msg += `\n`;
  });
  msg += `\n`;
}

if (msg.length <= 4096) return [{ json: { text: msg, isLast: true } }];
const chunks = []; let current = '';
for (const line of msg.split('\n')) {
  if ((current + line + '\n').length > 4000) { chunks.push(current.trim()); current = line + '\n'; }
  else current += line + '\n';
}
if (current.trim()) chunks.push(current.trim());
return chunks.map((text, index) => ({ json: { text, isLast: index === chunks.length - 1 } }));

const msg = $('Telegram Trigger').item.json.callback_query ? $('Telegram Trigger').item.json.callback_query.data : ($('Telegram Trigger').item.json.message.text || '');
const isOptimized = msg.toLowerCase().startsWith('/downloadoptimized');
const rawTailored = $('Supabase Fetch').item.json.tailored_profile;
const rawMaster = $('Supabase Fetch').item.json.master_profile;
const rawProfile = isOptimized ? rawTailored : rawMaster;

if (!rawProfile) {
  return [{
    json: {
      text: isOptimized
        ? "📭 No optimized resume yet. Use \`/optimize [paste JD here]\` to create one!"
        : "📭 No profile found. Please upload your resume PDF first!"
    }
  }];
}
const p = typeof rawProfile === 'string' ? JSON.parse(rawProfile) : rawProfile;

function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\textbackslash{}')
    .replace(/([&%$#{}])/g, '\\$1')
    .replace(/~/g, '\\textasciitilde{}')
    .replace(/\^/g, '\\textasciicircum{}')
    .replace(/_/g, '\\_');
}

function url(str) {
  if (!str) return '';
  // Only encode characters that would actually break LaTeX href parsing.
  // Do NOT apply esc() to URLs — it breaks underscores and # anchors.
  return String(str).replace(/%/g, '\\%').replace(/\\/g, '/');
}




function extractUrls(text) {
  if (!text) return [];
  const regex = /(?:https?:\/\/|www\.)[^\s,\|'"]+|[a-zA-Z0-9.-]+\.(?:com|app|net|io|me|dev|tech|co|org)(?:\/[^\s,\|'"]*)?/gi;
  return text.match(regex) || [];
}

function getValidUrl(urlStr, displayStr) {
  const urls = [];
  if (urlStr) urls.push(...extractUrls(urlStr));
  if (urls.length === 0 && displayStr) urls.push(...extractUrls(displayStr));
  if (urls.length > 0) {
      let u = urls[0];
      if (!u.startsWith('http')) u = 'https://' + u;
      return u;
  }
  return null;
}

const c = p.contact || {};

const headerLeft = [];
const headerRight = [];

headerLeft.push(`{\\LARGE \\textbf{${esc(p.name)}}}`);
if (p.tagline) {
  headerLeft.push(`\\textit{${esc(p.tagline.substring(0, 100))}}`);
}

if (c.email) {
  headerRight.push(`\\href{mailto:${url(c.email)}}{${esc(c.email)}}`);
}
if (c.phone) {
  const cleanPhone = c.phone.replace(/[^+\d]/g, '');
  headerRight.push(`\\href{tel:${cleanPhone}}{${esc(c.phone)}}`);
}
if (c.linkedin_url || c.linkedin_display) {
  const display = c.linkedin_display || 'LinkedIn';
  const u = getValidUrl(c.linkedin_url, c.linkedin_display);
  headerRight.push(u ? `\\href{${url(u)}}{${esc(display)}}` : esc(display));
}
if (c.github_url || c.github_display) {
  const display = c.github_display || 'GitHub';
  const u = getValidUrl(c.github_url, c.github_display);
  headerRight.push(u ? `\\href{${url(u)}}{${esc(display)}}` : esc(display));
}
if (c.portfolio_url || c.portfolio_display) {
  const display = c.portfolio_display || 'Portfolio';
  const u = getValidUrl(c.portfolio_url, c.portfolio_display);
  headerRight.push(u ? `\\href{${url(u)}}{${esc(display)}}` : esc(display));
}

const rows = Math.max(headerLeft.length, headerRight.length);
let headerBlock = '\\begin{tabular*}{\\textwidth}{l@{\\extracolsep{\\fill}}r}\n';
for (let i = 0; i < rows; i++) {
  const left = headerLeft[i] || '';
  const right = headerRight[i] || '';
  headerBlock += `  ${left} & ${right} \\\\\n`;
}
headerBlock += '\\end{tabular*}\n';


let eduBlock = '';
(p.education || []).forEach(e => {
  eduBlock += `  ${esc(e.degree)} & ${esc(e.institution)} & ${esc(e.score)} & ${esc(e.year)} \\\\\n  \\hline\n`;
});

let expBlock = '';
(p.work_experience || []).forEach(w => {
  expBlock += `  \\resumeSubheading{${esc(w.title)}}{${esc(w.location)}}{${esc(w.company)}}{${esc(w.start_date)} -- ${esc(w.end_date || 'Present')}}\n`;
  expBlock += `  \\resumeItemListStart\n`;
  (w.bullet_points || []).forEach(b => { expBlock += `    \\item {${esc(b)}}\n`; });
  expBlock += `  \\resumeItemListEnd\n`;
});

let projBlock = '';
(p.projects || []).forEach(proj => {
  let lTex = '';
  const urls = [];
  if (proj.link_url) urls.push(...extractUrls(proj.link_url));
  if (urls.length === 0 && proj.link_display) urls.push(...extractUrls(proj.link_display));
  if (urls.length > 0) {
    let liveDemo = null;
    let github = null;
    for (let u of urls) {
      if (!u.startsWith('http')) u = 'https://' + u;
      if (/github\.com/i.test(u)) github = u;
      else liveDemo = u;
    }
    if (liveDemo) lTex = `\\href{${url(liveDemo)}}{Live Demo}`;
    else if (github) lTex = `\\href{${url(github)}}{GitHub}`;
  }
  projBlock += `  \\resumeProject{${esc(proj.name)}}{${esc(proj.tech_stack)}}{${esc(proj.duration)}}{${lTex}}\n`;
  projBlock += `  \\resumeItemListStart\n`;
  (proj.bullet_points || []).forEach(b => { projBlock += `    \\item {${esc(b)}}\n`; });
  projBlock += `  \\resumeItemListEnd\n`;
});

let skillBlock = '';
(p.skills || []).forEach(s => {
  let items = '';
  if (Array.isArray(s.items)) items = s.items.join(', ');
  else if (typeof s.items === 'string') items = s.items;
  else if (s.skills) items = Array.isArray(s.skills) ? s.skills.join(', ') : s.skills;
  if (!items || !items.trim()) return;
  const cat = s.category || s.name || 'Skills';
  skillBlock += `  \\resumeSubItem{${esc(cat)}}{${esc(items)}}\n`;
});

let certBlock = '';
(p.certifications || []).forEach(cert => {
  certBlock += `  \\resumePOR{${esc(cert.issuer)}}{${esc(cert.name)}}{${esc(cert.year)}}\n`;
});

const tex = `\\documentclass[a4paper,11pt]{article}
\\usepackage{latexsym}
\\usepackage{xcolor}
\\usepackage{float}
\\usepackage{ragged2e}
\\usepackage[empty]{fullpage}
\\usepackage{wrapfig}
