\\section{Education}
\\setlength{\\tabcolsep}{5pt}
{\\small \\begin{tabularx}{\\linewidth}{|c|C|c|c|}
  \\hline
  \\textbf{Degree/Certificate} & \\textbf{Institute/Board} & \\textbf{Score} & \\textbf{Year}\\\\
  \\hline
${eduBlock}\\end{tabularx}}
\\vspace{2mm}

\\section{Experience}
\\resumeSubHeadingListStart
${expBlock}\\resumeSubHeadingListEnd
\\vspace{-5.5mm}

\\section{Projects}
\\resumeSubHeadingListStart
${projBlock}\\resumeSubHeadingListEnd
\\vspace{-5.5mm}

\\section{Technical Skills}
\\resumeHeadingSkillStart
