// ── Heuristic-first intent classification ─────────────────────────────────
// Run a fast local check before trusting the LLM classifier output.
// If the message clearly looks like a QUERY, short-circuit to QUERY.
// If it clearly looks like an UPDATE, short-circuit to UPDATE.
// Only fall back to the LLM's answer when neither heuristic matches.

const msg = ($('Telegram Trigger').first().json.message?.text || '').trim().toLowerCase();

const queryStarters = [
  'what', 'which', 'who', 'where', 'when', 'how many', 'how much',
  'do i have', 'did i', 'is my', 'are my', 'can you tell', 'show me',
  'list my', 'what are', 'what is', 'what was', 'what were',
  'tell me', 'give me', 'find my', 'check my', 'do i',
];

const updateStarters = [
  'add', 'update', 'change', 'set', 'remove', 'delete', 'fix', 'correct',
  'edit', 'replace', 'my new', 'i have', 'i got', 'i just', 'i completed',
  'i finished', 'i am working', 'i joined', 'i started', 'i built',
  'i created', 'i made', 'i earned', 'i received', 'my current',
];

const isLikelyQuery  = queryStarters.some(s  => msg.startsWith(s) || msg.includes(' ' + s + ' '));
const isLikelyUpdate = updateStarters.some(s => msg.startsWith(s));

// Heuristic: QUERY wins if no update-starter detected; UPDATE wins if explicit update language
let heuristicIntent = null;
if (isLikelyQuery && !isLikelyUpdate)  heuristicIntent = 'QUERY';
if (isLikelyUpdate && !isLikelyQuery)  heuristicIntent = 'UPDATE';

// Parse the LLM's output regardless (it's already been called upstream)
let rawText = $input.item.json.output || '';
let parsed = {};
try {
  let cleaned = rawText.replace(/```json|```/gi, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) cleaned = jsonMatch[0];
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { intent: 'UPDATE' };
}

// Apply heuristic override when confident
if (heuristicIntent) {
  parsed.intent = heuristicIntent;
}

// Sanitise: intent must be either QUERY or UPDATE
if (!['QUERY', 'UPDATE'].includes(parsed.intent)) {
  parsed.intent = 'UPDATE';
}

return [{ json: parsed }];

