// ── Safe Profile Merge ──────────────────────────────────────────────────────
// Guard against the AI returning a partial/wiped profile.
// We deep-merge the AI's master_profile with what's actually in Supabase,
// so no field can be silently erased by an incomplete LLM response.

const aiData = $input.item.json;
const aiProfile = aiData.master_profile;

// Fetch existing profile from Supabase
const rawExisting = $('Supabase Fetch').first().json.master_profile;
let existing = {};
try {
  existing = rawExisting
    ? (typeof rawExisting === 'string' ? JSON.parse(rawExisting) : rawExisting)
    : {};
} catch (e) {
  existing = {};
}

// If AI returned no profile or an empty object, keep existing and bail early
if (!aiProfile || typeof aiProfile !== 'object' || Object.keys(aiProfile).length === 0) {
  return [{ json: { ...aiData, master_profile: existing } }];
}

// ── Field-by-field merge ────────────────────────────────────────────────────
const merged = JSON.parse(JSON.stringify(existing)); // deep clone of existing

// Scalar fields: AI value wins only when it is a non-empty, non-whitespace string
const scalars = ['name', 'tagline', 'summary'];
for (const field of scalars) {
  if (aiProfile[field] != null && String(aiProfile[field]).trim() !== '') {
    merged[field] = aiProfile[field];
  }
}

// Contact sub-fields: merge at the sub-field level
if (aiProfile.contact && typeof aiProfile.contact === 'object') {
  merged.contact = merged.contact || {};
  for (const [key, val] of Object.entries(aiProfile.contact)) {
    if (val != null && String(val).trim() !== '') {
      merged.contact[key] = val;
    }
  }
}

// Array fields: AI array wins only when it contains at least one entry
// (an empty array from the AI means "I didn't touch this", not "delete it")
const arrays = ['skills', 'work_experience', 'education', 'projects', 'certifications'];
for (const field of arrays) {
  if (Array.isArray(aiProfile[field]) && aiProfile[field].length > 0) {
    merged[field] = aiProfile[field];
  }
}

// Pass through all other ai output fields unchanged (chat_reply, profile_updated, profile_status, etc.)
return [{ json: { ...aiData, master_profile: merged } }];
